package feedback

import (
	"context"
	"crypto/rand"
	"encoding/json"
	"fmt"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SubmitInput holds the data for a feedback submission.
type SubmitInput struct {
	Category    string
	Subject     string
	Description string
	Email       string // optional, for anonymous users
	UserAgent   string // optional
	PageURL     string // optional
	UserID      string // from JWT if authenticated
	UserEmail   string // from JWT if authenticated
}

// Service manages user feedback submissions.
type Service struct {
	pool *pgxpool.Pool
}

// NewService returns a new feedback service.
func NewService(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// validate checks that the required fields are present and within size limits.
func validate(input SubmitInput) error {
	if input.Subject == "" {
		return fmt.Errorf("feedback: subject is required")
	}
	if len(input.Subject) > 200 {
		return fmt.Errorf("feedback: subject exceeds 200 characters")
	}
	if input.Description == "" {
		return fmt.Errorf("feedback: description is required")
	}
	if len(input.Description) > 5000 {
		return fmt.Errorf("feedback: description exceeds 5000 characters")
	}
	return nil
}

// Submit validates and persists a feedback submission. Returns the generated ID.
func (s *Service) Submit(ctx context.Context, input SubmitInput) (string, error) {
	if err := validate(input); err != nil {
		return "", err
	}

	id, err := newUUID()
	if err != nil {
		return "", fmt.Errorf("feedback: generate id: %w", err)
	}

	data := map[string]string{
		"category":    input.Category,
		"subject":     input.Subject,
		"description": input.Description,
	}
	if input.UserAgent != "" {
		data["userAgent"] = input.UserAgent
	}
	if input.PageURL != "" {
		data["pageUrl"] = input.PageURL
	}

	dataJSON, err := json.Marshal(data)
	if err != nil {
		return "", fmt.Errorf("feedback: marshal data: %w", err)
	}

	// Determine user email: prefer JWT email, fall back to input email.
	email := input.UserEmail
	if email == "" {
		email = input.Email
	}

	// Use nil for empty optional strings so the DB stores NULL.
	var userID *string
	if input.UserID != "" {
		userID = &input.UserID
	}
	var userEmail *string
	if email != "" {
		userEmail = &email
	}

	var returnedID string
	err = s.pool.QueryRow(ctx,
		`INSERT INTO internal.user_feedback (id, user_id, user_email, data)
		 VALUES ($1, $2, $3, $4)
		 RETURNING id`,
		id, userID, userEmail, dataJSON,
	).Scan(&returnedID)
	if err != nil {
		return "", fmt.Errorf("feedback: insert: %w", err)
	}

	return returnedID, nil
}

// newUUID generates a UUID v4 string using crypto/rand.
func newUUID() (string, error) {
	var b [16]byte
	if _, err := rand.Read(b[:]); err != nil {
		return "", err
	}
	// Set version 4 and variant bits per RFC 4122.
	b[6] = (b[6] & 0x0f) | 0x40
	b[8] = (b[8] & 0x3f) | 0x80
	return fmt.Sprintf("%08x-%04x-%04x-%04x-%012x",
		b[0:4], b[4:6], b[6:8], b[8:10], b[10:16]), nil
}

package feedback

import (
	"strings"
	"testing"
)

func TestValidate_EmptySubject(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "",
		Description: "some description",
	})
	if err == nil {
		t.Fatal("expected error for empty subject")
	}
	if !strings.Contains(err.Error(), "subject is required") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_SubjectTooLong(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     strings.Repeat("a", 201),
		Description: "some description",
	})
	if err == nil {
		t.Fatal("expected error for long subject")
	}
	if !strings.Contains(err.Error(), "subject exceeds 200 characters") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_EmptyDescription(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "test subject",
		Description: "",
	})
	if err == nil {
		t.Fatal("expected error for empty description")
	}
	if !strings.Contains(err.Error(), "description is required") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_DescriptionTooLong(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "test subject",
		Description: strings.Repeat("a", 5001),
	})
	if err == nil {
		t.Fatal("expected error for long description")
	}
	if !strings.Contains(err.Error(), "description exceeds 5000 characters") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_ValidInput(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "Bug report",
		Description: "Something is broken.",
		Category:    "BUG",
	})
	if err != nil {
		t.Fatalf("expected no error, got: %v", err)
	}
}

func TestValidate_MaxLengthBoundary(t *testing.T) {
	// Exactly at the limit should pass.
	err := validate(SubmitInput{
		Subject:     strings.Repeat("a", 200),
		Description: strings.Repeat("b", 5000),
	})
	if err != nil {
		t.Fatalf("expected no error at boundary, got: %v", err)
	}
}

func TestNewUUID(t *testing.T) {
	id, err := newUUID()
	if err != nil {
		t.Fatalf("newUUID failed: %v", err)
	}
	if len(id) != 36 {
		t.Fatalf("expected 36-char UUID, got %d chars: %s", len(id), id)
	}
	// Check version nibble is 4.
	if id[14] != '4' {
		t.Fatalf("expected version 4, got %c at position 14", id[14])
	}

	// Ensure uniqueness.
	id2, err := newUUID()
	if err != nil {
		t.Fatalf("second newUUID failed: %v", err)
	}
	if id == id2 {
		t.Fatal("two UUIDs should not be equal")
	}
}

